// alertTriageGroup is one client's (or device's) open-alert roll-up line.
type alertTriageGroup struct {
	Group      string `json:"group"`
	Devices    int    `json:"devices"`
	OpenAlerts int    `json:"openAlerts"`
}

// alertTriageDetail is one synced alert record, when alert detail has been
// synced into the local store (sync cascades device -> alert).
type alertTriageDetail struct {
	Type          string `json:"type"`
	Priority      string `json:"priority"`
	Message       string `json:"message"`
	DateTriggered string `json:"dateTriggered"`
}

// alertTriageReport is the fleet-wide alert triage view.
type alertTriageReport struct {
	GroupBy     string              `json:"groupBy"`
	Groups      []alertTriageGroup  `json:"groups"`
	TotalAlerts int                 `json:"totalAlerts"`
	Details     []alertTriageDetail `json:"details"`
	Note        string              `json:"note,omitempty"`
}

// alertPriorityRank orders alert priorities highest-first for triage.
// Unknown or empty priorities sink to the bottom.
func alertPriorityRank(priority string) int {
	switch strings.ToLower(strings.TrimSpace(priority)) {
	case "critical":
		return 0
	case "high", "error":
		return 1
	case "medium", "warning":
		return 2
	case "low", "info":
		return 3
	default:
		return 4
	}
}

// pp:data-source local
func newNovelAlertTriageCmd(flags *rootFlags) *cobra.Command {
	var flagGroupBy string
	var dbPath string

	cmd := &cobra.Command{
		Use:   "alert-triage",
		Short: "Every open alert across the whole fleet in one ranked view, grouped by client and device",
		Long: strings.Trim(`
Use this command to triage raw open alerts fleet-wide grouped by client.
Do NOT use it for a weighted cross-signal risk score; use 'client-risk' instead.

The roll-up ranks clients (or devices, with --group-by device) by their open
alert counts from the synced device records. When alert detail rows have been
synced (sync cascades device -> alert), the report also lists each alert's
type, priority, message, and trigger date, ordered highest priority first.`, "\n"),
		Example: strings.Trim(`
  # Morning triage: which clients have the most open alerts
  datto-bcdr-cli alert-triage --group-by client --json

  # Same roll-up per appliance
  datto-bcdr-cli alert-triage --group-by device --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would rank fleet-wide open alerts from the local store")
				return nil
			}
			if err := validateDataSourceStrategy(flags, "local"); err != nil {
				return err
			}
			groupBy := strings.ToLower(strings.TrimSpace(flagGroupBy))
			if groupBy == "" {
				groupBy = "client"
			}
			if groupBy != "client" && groupBy != "device" {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("--group-by must be 'client' or 'device', got %q", flagGroupBy))
			}
			if dbPath == "" {
				dbPath = defaultDBPath("datto-bcdr-cli")
			}
			db, err := nvOpenStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer db.Close()

			if !hintIfUnsynced(cmd, db, "") {
				hintIfStale(cmd, db, "", flags.maxAge)
			}

			report := alertTriageReport{
				GroupBy: groupBy,
				Groups:  make([]alertTriageGroup, 0),
				Details: make([]alertTriageDetail, 0),
			}

			// Roll-up from device records: alertCount is the per-appliance
			// open-alert counter the API maintains, so the ranking works even
			// before alert detail rows have been synced.
			devRows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.clientCompanyName'), ''),
					COALESCE(json_extract(data,'$.serialNumber'), ''),
					COALESCE(json_extract(data,'$.name'), ''),
					json_extract(data,'$.alertCount')
				FROM "device"`)
			if err != nil {
				return fmt.Errorf("querying devices: %w", err)
			}
			defer devRows.Close()

			agg := map[string]*alertTriageGroup{}
			order := []string{}
			for devRows.Next() {
				var (
					client, serial, name string
					alertCount           sql.NullInt64
				)
				if err := devRows.Scan(&client, &serial, &name, &alertCount); err != nil {
					return fmt.Errorf("scanning device: %w", err)
				}
				key := client
				if groupBy == "device" {
					key = serial
					if name != "" {
						key = fmt.Sprintf("%s (%s)", name, serial)
					}
				}
				g, ok := agg[key]
				if !ok {
					g = &alertTriageGroup{Group: key}
					agg[key] = g
					order = append(order, key)
				}
				g.Devices++
				if alertCount.Valid {
					g.OpenAlerts += int(alertCount.Int64)
					report.TotalAlerts += int(alertCount.Int64)
				}
			}
			if err := devRows.Err(); err != nil {
				return fmt.Errorf("iterating devices: %w", err)
			}
			devRows.Close()

			for _, key := range order {
				report.Groups = append(report.Groups, *agg[key])
			}
			// Most alerts first; stable on group name for determinism.
			sort.SliceStable(report.Groups, func(i, j int) bool {
				if report.Groups[i].OpenAlerts != report.Groups[j].OpenAlerts {
					return report.Groups[i].OpenAlerts > report.Groups[j].OpenAlerts
				}
				return report.Groups[i].Group < report.Groups[j].Group
			})

			// Alert detail rows, when synced. The Datto alert payload does not
			// embed the device serial, so details enrich the roll-up rather
			// than replace it.
			alRows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.type'), ''),
					COALESCE(json_extract(data,'$.priority'), ''),
					COALESCE(json_extract(data,'$.message'), ''),
					COALESCE(json_extract(data,'$.dateTriggered'), '')
				FROM "alert"`)
			if err != nil {
				return fmt.Errorf("querying alerts: %w", err)
			}
			defer alRows.Close()
			for alRows.Next() {
				var d alertTriageDetail
				if err := alRows.Scan(&d.Type, &d.Priority, &d.Message, &d.DateTriggered); err != nil {
					return fmt.Errorf("scanning alert: %w", err)
				}
				report.Details = append(report.Details, d)
			}
			if err := alRows.Err(); err != nil {
				return fmt.Errorf("iterating alerts: %w", err)
			}
			// Highest priority first, newest first within a priority band.
			sort.SliceStable(report.Details, func(i, j int) bool {
				ri, rj := alertPriorityRank(report.Details[i].Priority), alertPriorityRank(report.Details[j].Priority)
				if ri != rj {
					return ri < rj
				}
				return report.Details[i].DateTriggered > report.Details[j].DateTriggered
			})

			if len(report.Details) == 0 && report.TotalAlerts > 0 {
				report.Note = "alert detail rows not synced yet; counts come from device alertCount — run 'datto-bcdr-cli sync --resources device' to cascade alert detail"
			}
			if report.TotalAlerts == 0 && len(report.Groups) == 0 {
				report.Note = "no synced devices found; run 'datto-bcdr-cli sync' first"
			}

			return flags.printJSON(cmd, report)
		},
	}
	cmd.Flags().StringVar(&flagGroupBy, "group-by", "client", "Group open alerts by 'client' or 'device'")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (defaults to standard location)")
	return cmd
}
